import React from "react";
import fllledStar from "@styles/assets/images/hire-devs/filledstar.svg";
import unFllledStar from "@styles/assets/images/hire-devs/unfilledstar.svg";
import quotes from "@images/hirescreens/devPages/icons/quotes.png";

const boxData = [
  {
    id: 1,
    rating: 4,
    name: "Deepak Selvam",
    review:
      "The React team delivered a fast, responsive, and scalable web app. Their communication was excellent, and the project exceeded our expectations.",
  },
  {
    id: 2,
    rating: 4,
    name: "Sanjay Prakash",
    review:
      "Our ideas were transformed into a modern, interactive React application. The team was skilled, professional, and delivered the project on time with exceptional quality.",
  },
  {
    id: 3,
    rating: 4,
    name: "Suresh Rajan",
    review:
      "We are very happy with the React development services. The team delivered a high-quality, reliable, and future-ready application with clear and consistent communication.",
  },
];

const clientsreviews = () => {
  const totalStars = 5;

  return (
    <section className="hero-wrapper item-center gap-xl">
      <div className="item-center gap-sm">
        <h2 className="about-h2 font-black">Client Reviews</h2>
      </div>
      <div className="mean-and-mern-review-cards c-grid grid-three w-100">
        {boxData.map((item, idx) => (
          <div
            className="mean-and-mern-review-card item-start gap-xl"
            key={idx}
          >
            <div className="item-start gap-sm">
              <img src={quotes} alt="quotes" />
              <div>
                {[...Array(totalStars)].map((_, index) => (
                  <img
                    key={index}
                    src={index < item.rating ? fllledStar : unFllledStar}
                    alt={index < item.rating ? "filled star" : "unfilled star"}
                  />
                ))}
              </div>
              <p className="about-p-two light-gray">{item.review}</p>
            </div>
            <p className="about-p font-black fw-600 ">-{item.name}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default clientsreviews;
