import { Justtrylinks } from "@components/common/justtrylinks";
import { Link } from "@reach/router";
import React from "react";

const boxData = [
  {
    id: 1,
    number: 5,
    isPercentage: false,
    title: "Full Stack Developers Available",
  },
  {
    id: 2,
    number: 120,
    isPercentage: false,
    title: "Projects Delivered",
  },
  {
    id: 3,
    number: 15,
    isPercentage: false,
    title: "Industries Served",
  },
  {
    id: 4,
    number: 98,
    isPercentage: true,
    title: "Client Retention Rate",
  },
];

const about = () => {
  return (
    <section className="light-gray-bg">
      <div className="hero-wrapper-v2 ">
        <div className="hero-wrapper item-center gap-md">
          <span className="gradient-badge-v2">About</span>
          <h2 className="about-h2 c-text-center">
            MEAN and MERN stack development
          </h2>
          <p className="about-p c-text-center md-c-text-start">
            These two{" "}
            <Link to={Justtrylinks.hireDevelopers}>
              software development services
            </Link>{" "}
            are the most robust and versatile full-stack JavaScript systems used
            to develop dynamic and high-performance web applications. Both
            stacks are similar regarding the use of MongoDB, Express.js, and
            Node.js, which allow back-end development and real-time data
            processing, as well as smooth API integrations. The primary
            distinction is that the front-end technologies of MERN (React) and
            MEAN (Angular) are more flexible and flexible component-based
            interfaces and a more structured and enterprise-ready framework,
            respectively. Collectively, these stacks enable developers to
            develop with a single language throughout the project and save time
            on development, as well as enhance consistency.
          </p>
        </div>
        <div className="achievements-mean-mern-section c-grid grid-four gap-lg">
          {boxData.map((item) => (
            <div key={item.id} className="item-center gap-sm">
              <span className="about-h3 font-white">
                {item.number}
                {item.isPercentage ? "%" : "+"}
              </span>
              <p className="about-p-two font-white c-text-center">
                {item.title}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default about;
