import React from "react";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import { graphql } from "gatsby";
import Seo from "@components/seo";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
// import MoveForward from "@components/common/move-forward";
import MernDevelopmentScreen from "@screens/mern-development";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const MernDevelopment = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "MEAN/MERN Development Services", link: null },
  ];
  const { data } = props;
  const logoObj = data?.allImageSharp?.edges?.find((image) => {
    return image?.node?.gatsbyImageData?.images?.fallback?.src?.includes(
      "new_logo.png",
    );
  });
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "MEAN and MERN full-stack development we deliver modern web apps using JavaScript, databases, and powerful frameworks.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1599",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is MEAN and MERN full stack?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "MEAN and MERN full-stack are JavaScript-based technologies used to build complete web applications from frontend to backend.",
            },
          },
          {
            "@type": "Question",
            name: "Which is better, MEAN or MERN stack?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "MEAN is better for large, structured enterprise apps, while MERN is better for fast, interactive, and highly dynamic user interfaces.",
            },
          },
          {
            "@type": "Question",
            name: "What are the skills required for a MERN stack developer?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A MERN stack developer needs skills in JavaScript, React (frontend), Node.js & Express (backend), MongoDB (database), along with HTML, CSS, Git, REST APIs, and basic deployment knowledge.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={logoObj?.node?.gatsbyImageData?.images?.fallback?.src}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <MernDevelopmentScreen db={db} />
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default MernDevelopment;

export const queryData = graphql`
  query MyQuery {
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allImageSharp {
      edges {
        node {
          gatsbyImageData
          id
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "mean-and-mern-full-stack-development" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
