import Faqv2 from "@components/common/faq-v2";
import React from "react";

const faq = () => {
  const data = [
    {
      question: "What’s the difference between MEAN and MERN?",
      answer:
        "MERN uses React for the frontend, while MEAN uses Angular. Both share MongoDB, Express.js, and Node.js.",
    },
    {
      question: "Are MEAN/MERN suitable for large-scale applications?",
      answer:
        "Yes. Both stacks are scalable, flexible, and used widely for medium to large applications.",
    },
    {
      question: "Will my application be mobile-friendly?",
      answer:
        "Yes. We build responsive, fast, and user-friendly interfaces in both stacks.",
    },
    {
      question: "Which one should I choose?",
      answer:
        "Choose MERN for flexibility or MEAN for structured enterprise solutions.",
    },
  ];
  return (
    <section className="faq-section">
      <div className="hero-wrapper bg-black-faq">
        <Faqv2 faqData={data} />
      </div>
    </section>
  );
};

export default faq;
